// Dedupe events that appear on multiple calendars + build a WhatsApp message.
// Dedup key: iCalUID (same meeting across calendars shares this) -> id -> summary|start.
// Skips any event whose meeting id is in `ignoreEventIds` (no notification).
//   For recurring meetings, list the base id (recurringEventId, e.g.
//   "m0bootqje4soor32cuinkmhh13") to mute the whole series forever.
//   For a one-off, list its event id. The per-occurrence id
//   (base_20260627T123000Z) and the iCalUID are also matched.
// Outputs nothing if there are no events left in the next hour.

const TZ = 'Asia/Kolkata';
const now = new Date();
const windowEnd = new Date(now.getTime() + 60 * 60 * 1000);

// Ignore list comes from the 'Calendar IDs' Set node variable.
const ignore = new Set(
  ($('Calendar IDs').first().json.ignoreEventIds || []).map((s) =>
    String(s).toLowerCase()
  )
);

// An event is ignored if ANY of its identifiers is in the ignore list:
//   - recurringEventId (base id, constant across the whole series)
//   - id (per-occurrence: base_<timestamp>)
//   - iCalUID (constant across all instances)
// An event is ignored if ANY of its identifiers MATCHES or STARTS WITH an
// ignore entry. We strip the per-occurrence "_<timestamp>" suffix and the
// "@google.com" from iCalUID, then prefix-match — so a base id like
// "5ckvlnl8on2acila36n4m01vv5" catches "5ckvlnl8on2acila36n4m01vv5_R20260511T133000".
const isIgnored = (e) => {
  const ids = [e.recurringEventId, e.id, e.iCalUID]
    .filter(Boolean)
    .map((s) => String(s).toLowerCase().replace(/@google\.com$/, ''));
  for (const id of ids) {
    for (const ig of ignore) {
      if (id === ig || id.startsWith(ig)) return true;
    }
  }
  return false;
};


// Resolve which calendar (email/id) an event was fetched from, via item
// pairing back to the 'Split Out Calendar IDs' node (each item carried
// `calendarId`). Falls back to organizer email if pairing is unavailable.
const sourceCalOf = (item, e) => {
  try {
    const idx = item.pairedItem?.item ?? item.pairedItem;
    const src = $('Split Out Calendar IDs').itemMatching(idx);
    if (src?.json?.calendarId) return src.json.calendarId;
  } catch (err) {
    // ignore and fall through
  }
  return e?.organizer?.email || '';
};

const getStart = (e) => e?.start?.dateTime || e?.start?.date || '';
const getEnd = (e) => e?.end?.dateTime || e?.end?.date || '';
const dedupKey = (e) => e.iCalUID || e.id || `${e.summary}|${getStart(e)}`;

const seen = new Map();
for (const item of items) {
  const e = item.json;
  if (!e || !e.summary) continue;
  if (e.status === 'cancelled') continue;

  // skip muted meetings (by recurring base id / event id / iCalUID)
  if (isIgnored(e)) continue;

  const startStr = getStart(e);
  if (!startStr) continue;
  const startDate = new Date(startStr);
  // keep only events that start within now -> +1h
  if (isNaN(startDate) || startDate < now || startDate > windowEnd) continue;

  // tag the event with the calendar it came from
  e._sourceCalendar = sourceCalOf(item, e);

  const key = dedupKey(e);
  // prefer the copy where Lakshit is flagged self / most recently updated
  if (!seen.has(key)) {
    seen.set(key, e);
  } else {
    const prev = seen.get(key);
    const prevUpd = new Date(prev.updated || 0);
    const curUpd = new Date(e.updated || 0);
    if (curUpd > prevUpd) seen.set(key, e);
  }
}

const events = Array.from(seen.values()).sort(
  (a, b) => new Date(getStart(a)) - new Date(getStart(b))
);

// no events -> emit nothing (nothing gets sent over WhatsApp)
if (events.length === 0) {
  return [];
}

const fmtTime = (iso) =>
  new Date(iso).toLocaleTimeString('en-IN', {
    hour: '2-digit',
    minute: '2-digit',
    hour12: true,
    timeZone: TZ,
  });

const lines = events.map((e) => {
  const time = `${fmtTime(getStart(e))} - ${fmtTime(getEnd(e))}`;
  const title = e.summary || '(no title)';
  const cal = e._sourceCalendar || '';
  const link = e.hangoutLink || e.location || '';
  let line = `\u2022 *${time}*  ${title}`;
  if (cal) line += `\n   \uD83D\uDCC7 ${cal}`;
  if (link) line += `\n   \u21B3 ${link}`;
  return line;
});

const header =
  events.length === 1
    ? '\uD83D\uDCC5 *Upcoming in the next hour*'
    : `\uD83D\uDCC5 *Upcoming in the next hour (${events.length})*`;

const message = `${header}\n\n${lines.join('\n\n')}`;

return [
  {
    json: {
      count: events.length,
      message,
      events,
    },
  },
];

